import java.util.*;

public class ConnectedComponents {

    public int countComponents(Map<Integer, List<Integer>> graph) {
        Set<Integer> visited = new HashSet<>();
        int count = 0;
        for (int vertex : graph.keySet()) {
            if (!visited.contains(vertex)) {
                dfs(graph, vertex, visited);
                count++;
            }
        }
        return count;
    }

    private void dfs(Map<Integer, List<Integer>> graph, int node, Set<Integer> visited) {
        visited.add(node);
        for (int neighbor : graph.getOrDefault(node, Collections.emptyList())) {
            if (!visited.contains(neighbor)) dfs(graph, neighbor, visited);
        }
    }

    public Map<Integer, Integer> componentMap(Map<Integer, List<Integer>> graph) {
        // TODO: return map vertex -> component number (0-indexed)
        // Use same approach as countComponents but label each visited set
        return new HashMap<>();
    }

    public static void main(String[] args) {
        ConnectedComponents cc = new ConnectedComponents();
        Map<Integer, List<Integer>> g = new LinkedHashMap<>();
        g.put(0, Arrays.asList(1, 2));
        g.put(1, Arrays.asList(0));
        g.put(2, Arrays.asList(0));
        g.put(3, Arrays.asList(4));
        g.put(4, Arrays.asList(3));
        System.out.println("Components: " + cc.countComponents(g));
        System.out.println("Map: " + new TreeMap<>(cc.componentMap(g)));
    }
}
